import{_ as s,c as a,o as i,b as d}from"./app.6039188d.js";const u='{"title":"\u0413\u043B\u0430\u0432\u0430 5","description":"","frontmatter":{"title":"\u0413\u043B\u0430\u0432\u0430 5","subtitle":"\u041C\u0430\u043B\u0438\u043D\u0438 \u0432\u0438\u0434\u0436\u0430\u0439\u043E\u0442\u0442\u0430\u0440\u0430 \u0442\u0430\u043D\u0442\u0440\u0430","tags":"malini","date":"2020-10-10T00:00:00.000Z"},"headers":[],"relativePath":"texts/malini-vijayottara/5/index.md"}',t={},n=d('<p>\u0428\u0438\u0432\u0430 \u0441\u043A\u0430\u0437\u0430\u043B:</p><div class="stanza"><a href="#s5.1-2" id="s5.1-2" class="num">5.1-2</a><p>\u0422\u0435\u043F\u0435\u0440\u044C \u043F\u043E\u0432\u0435\u0434\u0430\u044E, \u043E \u0412\u043B\u0430\u0434\u044B\u0447\u0438\u0446\u0430, \u043E \u0440\u0430\u0441\u043F\u043E\u043B\u043E\u0436\u0435\u043D\u0438\u0438 \u043C\u0438\u0440\u043E\u0432. \u0412 \u043D\u0430\u0447\u0430\u043B\u0435 (\u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442) \u043E\u0447\u0438\u0449\u0430\u044E\u0449\u0438\u0439 \u043C\u0438\u0440 \u041A\u0430\u043B\u0430\u0433\u043D\u0438, (\u0437\u0430\u0442\u0435\u043C), \u0442\u0440\u0438 (\u043C\u0438\u0440\u0430) \u0430\u0432\u0438\u0447\u0438 - \u041A\u0443\u043C\u0431\u0438\u043F\u0430\u043A\u0430, \u0420\u0430\u0443\u0440\u0430\u0432\u0430 \u0438 \u041A\u0443\u0448\u043C\u0430\u043D\u0434\u0430. \u0412\u0441\u0435 \u044D\u0442\u0438 \u043C\u0438\u0440\u044B \u0447\u0438\u0441\u0442\u044B, \u043D\u0435\u0442 \u0432 \u0442\u043E\u043C \u0441\u043E\u043C\u043D\u0435\u043D\u0438\u044F .</p></div><div class="stanza"><a href="#s5.3-4" id="s5.3-4" class="num">5.3-4</a><p>\u0417\u0430\u0442\u0435\u043C \u0441\u043B\u0435\u0434\u0443\u044E\u0442 \u0441\u0435\u043C\u044C \u043F\u0430\u0442\u0430\u043B. \u0418\u0437 \u043D\u0438\u0445 \u043F\u0435\u0440\u0432\u0430\u044F - \u041C\u0430\u0445\u0430\u0442\u0430\u043B\u0430. \u0417\u0430\u0442\u0435\u043C - \u0440\u0430\u0441\u0430\u0442\u0430\u043B\u0430, \u0442\u0430\u043B\u0430\u0442\u0430\u043B\u0430, \u0441\u0443\u0442\u0430\u043B\u0430, \u043D\u0438\u0442\u0430\u043B\u0430, \u0432\u0438\u0442\u0430\u043B\u0430 \u0438 \u0442\u0430\u043B\u0430. \u0412\u0441\u0435 \u043E\u043D\u0438 \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u044E\u0442\u0441\u044F \u0447\u0438\u0441\u0442\u044B\u043C\u0438 \u0438 \u0437\u043E\u043B\u043E\u0442\u044B\u043C\u0438 .</p></div><div class="stanza"><a href="#s5.5" id="s5.5" class="num">5.5</a><p>\u0412\u044B\u0448\u0435 \u044D\u0442\u043E\u0433\u043E - \u0417\u0435\u043C\u043B\u044F, \u043D\u0430\u0434\u0435\u043B\u0435\u043D\u043D\u0430\u044F \u0441\u0435\u043C\u044C\u044E \u043E\u0441\u0442\u0440\u043E\u0432\u0430\u043C\u0438. \u0412 \u0446\u0435\u043D\u0442\u0440\u0435 \u0435\u0435 \u043D\u0430\u0445\u043E\u0434\u0438\u0442\u0441\u044F \u041C\u0435\u0440\u0443 - \u043E\u0431\u0438\u0442\u0435\u043B\u044C \u0431\u043E\u0433\u043E\u0432 .</p></div><div class="stanza"><a href="#s5.6" id="s5.6" class="num">5.6</a><p>\u0412\u044B\u0448\u0435 \u0435\u0435 \u0431\u0445\u0443\u0432\u0430\u043B\u043E\u043A\u0430, \u043D\u0430\u0434 \u043D\u0435\u044E - \u0441\u0432\u0430\u0440\u0433\u0430\u043B\u043E\u043A\u0430, \u0434\u0430\u043B\u0435\u0435 \u043C\u0430\u0445\u0430, \u0434\u0436\u0430\u043D\u0430, \u0442\u0430\u043F\u0430 \u0438 \u0441\u0430\u0442\u044C\u044F (\u043B\u043E\u043A\u0438). \u0422\u0430\u043A\u043E\u0432\u0430 \u0441\u0435\u043C\u0435\u0440\u043A\u0430 \u043C\u0438\u0440\u043E\u0432 .</p></div><div class="stanza"><a href="#s5.7-10" id="s5.7-10" class="num">5.7-10</a><p>(\u0421\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442) \u0447\u0435\u0442\u044B\u0440\u043D\u0430\u0434\u0446\u0430\u0442\u044C \u0432\u0438\u0434\u043E\u0432 \u0441\u0443\u0449\u0435\u0441\u0442\u0432, \u0432 \u043A\u043E\u0442\u043E\u0440\u044B\u0445 \u0438 \u0434\u0435\u0439\u0441\u0442\u0432\u0443\u0435\u0442 \u0441\u043E\u043D\u043C \u0441\u0443\u0449\u0435\u0441\u0442\u0432 \u043D\u0435\u043F\u043E\u0434\u0432\u0438\u0436\u043D\u044B\u0445, \u0440\u043E\u0436\u0434\u0435\u043D\u043D\u044B\u0445 \u0437\u0432\u0435\u0440\u044F\u043C\u0438, \u0437\u043C\u0435\u044F\u043C\u0438 \u0438 \u043F\u0442\u0438\u0446\u0430\u043C\u0438. \u041E\u043D\u0438 \u0438\u043C\u0435\u043D\u0443\u044E\u0442\u0441\u044F \u043F\u044F\u0442\u044C\u044E \u0432\u0438\u0434\u0430\u043C\u0438 \u0436\u0438\u0432\u043E\u0442\u043D\u044B\u0445. \u0427\u0435\u043B\u043E\u0432\u0435\u043A - \u0438\u043D\u043E\u0435. \u041F\u0438\u0448\u0430\u0447\u0438, \u0440\u0430\u043A\u0448\u0430\u0441\u044B, \u044F\u043A\u0448\u0438, \u0433\u0430\u043D\u0434\u0445\u0430\u0440\u0432\u044B, \u0418\u043D\u0434\u0440\u0430, \u0421\u043E\u043C\u0430, \u041F\u0440\u0430\u0434\u0436\u0430\u043F\u0430\u0442\u0438, \u0411\u0440\u0430\u0445\u043C\u0430. (\u0438\u0442\u043E\u0433\u043E): \u0447\u0435\u0442\u044B\u0440\u043D\u0430\u0434\u0446\u0430\u0442\u044C. \u0412\u0441\u0435 \u043E\u043D\u0438 \u0447\u0438\u0441\u0442\u044B\u0435 \u0432 \u043C\u0438\u0440\u0435 \u0411\u0440\u0430\u0445\u043C\u044B. (\u0412\u044B\u0448\u0435) \u043D\u0435\u0433\u043E - \u043C\u0438\u0440 \u0412\u0438\u0448\u043D\u0443, \u0435\u0449\u0435 \u0432\u044B\u0448\u0435 - \u041C\u043E\u0439 \u043C\u0438\u0440. \u0412 \u0442\u043E\u0439 \u0447\u0438\u0441\u0442\u043E\u0442\u0435 \u0447\u0438\u0441\u0442\u043E \u0432\u0441\u0435, \u0431\u0435\u0437 \u0441\u043E\u043C\u043D\u0435\u043D\u0438\u044F .</p></div><div class="stanza"><a href="#s5.11" id="s5.11" class="num">5.11</a><p>\u041E, \u0412\u043E\u0437\u043B\u044E\u0431\u043B\u0435\u043D\u043D\u0430\u044F, \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u044D\u0442\u0438\u043C \u0447\u0438\u0441\u0442\u044B\u043C \u043F\u044F\u0442\u0438 \u043C\u0438\u0440\u0430\u043C, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u041A\u0430\u043B\u0430\u0433\u043D\u0438, \u0432\u0441\u0435 \u0432\u043E \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439 \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u0447\u0438\u0441\u0442\u044B\u043C .</p></div><div class="stanza"><a href="#s5.12" id="s5.12" class="num">5.12</a><p>\u0421\u043D\u0430\u0440\u0443\u0436\u0438 \u0438\u0445 \u043D\u0430\u0445\u043E\u0434\u044F\u0442\u0441\u044F \u043F\u043E \u043E\u0442\u0434\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438 \u043C\u0438\u0440\u044B \u0441\u0442\u0430 \u0440\u0443\u0434\u0440, (\u0432 \u043A\u043E\u0442\u043E\u0440\u044B\u0445) \u043E\u0434\u0438\u043D \u0432\u043B\u0430\u0434\u044B\u043A\u0430 \u043E\u0447\u0438\u0449\u0430\u0435\u0442 \u0434\u0435\u0441\u044F\u0442\u043E\u043A (\u043C\u0438\u0440\u043E\u0432) .</p></div><div class="stanza"><a href="#s5.13-14" id="s5.13-14" class="num">5.13-14</a><p>\u041F\u0435\u0440\u0432\u044B\u0439 - \u0410\u043D\u0430\u043D\u0442\u0430, \u0437\u0430\u0442\u0435\u043C - \u041A\u0430\u043F\u0430\u043B\u0438\u0448\u0430, \u0410\u0433\u043D\u0438\u0440\u0443\u0434\u0440\u0430, \u042F\u043C\u0430, \u041D\u0440\u0442\u0438, \u0411\u0430\u043B\u0430, \u0428\u0438\u0433\u0445\u0440\u0430, \u041D\u0438\u0434\u0445\u0438\u0448\u0432\u0430\u0440\u0430, \u0412\u0438\u0434\u0445\u0443\u043C\u0430\u0434\u0434\u0436\u0430\u0432\u0430\u043B\u0430\u043D\u0430\u043F\u0440\u0430\u0431\u0445\u0430,</p></div><div class="stanza"><a href="#s5.15" id="s5.15" class="num">5.15</a><p>\u042D\u0442\u043E\u0439 \u0434\u0435\u0441\u044F\u0442\u043A\u043E\u0439 \u0447\u0438\u0441\u0442\u044B\u0445 \u043E\u0447\u0438\u0449\u0430\u0435\u0442\u0441\u044F \u0441\u043E\u0442\u043D\u044F. \u0412\u044B\u0448\u0435 \u043F\u0440\u0435\u0434\u044B\u0434\u0443\u0449\u0438\u0445 \u043D\u0430\u0445\u043E\u0434\u0438\u0442\u0441\u044F \u043F\u044F\u0442\u044C \u0432\u043E\u0441\u044C\u043C\u0435\u0440\u043E\u043A (\u0420\u0443\u0434\u0440) .</p></div><div class="stanza"><a href="#s5.16" id="s5.16" class="num">5.16</a><p>\u041B\u0430\u043A\u0443\u043B\u0438, \u0411\u0445\u0430\u0440\u0430\u0431\u0445\u0443\u0442\u0438, \u0414\u0438\u043D\u0434\u044C\u044F\u0448\u0430\u0434\u0445\u0438, \u041F\u0443\u0448\u043A\u0430\u0440\u0430, \u041D\u0430\u0439\u043C\u0438\u0448\u0430, \u041F\u0440\u0430\u0431\u0445\u0430\u0441\u0430, \u0410\u043C\u0430\u0440\u0435\u0448\u0430: \u0442\u0430\u043A\u043E\u0432\u0430 (\u043F\u0435\u0440\u0432\u0430\u044F) \u0432\u043E\u0441\u044C\u043C\u0435\u0440\u043A\u0430 .</p></div><div class="stanza"><a href="#s5.17-20" id="s5.17-20" class="num">5.17-20</a><p>\u042D\u0442\u043E \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u0432\u043E\u0441\u044C\u043C\u0435\u0440\u043A\u043E\u0439 \u0433\u043E\u0441\u043F\u043E\u0434. \u0422\u0435\u043F\u0435\u0440\u044C (\u0440\u0430\u0441\u0441\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F) \u0442\u0430\u0439\u043D\u0430 \u0442\u0430\u0439\u043D. \u042D\u0442\u043E - \u0411\u0445\u0430\u0439\u0440\u0430\u0432\u0430, \u041A\u0435\u0434\u0430\u0440\u0430, \u041C\u0430\u0445\u0430\u043A\u0430\u043B\u0430, \u041C\u0430\u0434\u0445\u044C\u044F\u043C\u0430, \u0410\u043C\u0440\u0430\u0442\u0438\u043A\u0435\u0448\u0430, \u0414\u0436\u0430\u043B\u043F\u0435\u0448\u0430, \u0428\u0440\u0438 \u0428\u0430\u0439\u043B\u0430, \u0425\u0430\u0440\u0438\u043D\u0434\u0440\u0430\u0432\u0430, \u0411\u0445\u0438\u043C\u0435\u0448\u0432\u0430\u0440\u0430, \u041C\u0430\u0445\u0435\u043D\u0434\u0440\u0430, \u0410\u0434\u0440\u0438\u0445\u0430\u0441\u0430, \u0412\u0438\u043C\u0430\u043B\u0435\u0448\u0432\u0430\u0440\u0430, \u041A\u0430\u043D\u0430\u043A\u0445\u0430\u043B\u0430, \u041D\u0430\u043A\u0445\u0430\u043B\u0430, \u041A\u0443\u0440\u0443\u043A\u0448\u0435\u0442\u0440\u0430, \u0413\u0430\u044F: \u044D\u0442\u043E \u0442\u0440\u0435\u0442\u044C\u044F, \u0442\u0430\u0439\u043D\u0430\u044F (\u0432\u043E\u0441\u044C\u043C\u0435\u0440\u043A\u0430). \u0422\u0435\u043F\u0435\u0440\u044C \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u043E\u0447\u0438\u0449\u0430\u044E\u0449\u0430\u044F (\u0432\u043E\u0441\u044C\u043C\u0435\u0440\u043A\u0430): \u0421\u0442\u0445\u0430\u043D\u0443, \u0421\u0443\u0432\u0430\u0440\u043D\u0430, \u0410\u043A\u0448\u0430\u043A\u0430, \u0412\u0430\u0434\u0439\u0430, \u0411\u0445\u0430\u0434\u0440\u0430\u0433\u0430, \u041A\u0430\u0440\u043D\u0430\u043A\u0430, \u041C\u0430\u0445\u0430\u043A\u0430\u043B\u0430, \u0412\u0438\u043C\u0443\u043A\u0442\u0435\u0448\u0430, \u0420\u0443\u0434\u0440\u0430\u043A\u043E\u0442\u0438, \u0410\u043C\u0431\u0430\u0440\u0430\u043F\u0430\u0434\u0430 .</p></div><div class="stanza"><a href="#s5.21-22" id="s5.21-22" class="num">5.21-22</a><p>\u0414\u0430\u043B\u0435\u0435 (\u0441\u043B\u0435\u0434\u0443\u044E\u0442): \u0421\u0442\u0445\u0443\u043B\u0430, \u0421\u0442\u0445\u0443\u043B\u0435\u0448\u0432\u0430\u0440\u0430, \u0428\u0430\u043D\u043A\u0443\u043A\u0430\u0440\u043D\u0430\u043A\u0430, \u0410\u043B\u0430\u043D\u0434\u0436\u0430\u0440\u0430, \u041C\u0430\u043D\u0434\u0430\u043B\u0435\u0448\u0432\u0430\u0440\u0430, \u041C\u0430\u043A\u043E\u0442\u0430, \u0414\u0443\u0440\u0430\u043D\u0434\u0430, \u0427\u0445\u0430\u0433\u0430, \u041B\u0430\u043D\u0434\u0430\u043A\u0430. \u042D\u0442\u043E \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u0432\u043E\u0441\u044C\u043C\u0435\u0440\u043A\u043E\u0439 \u0442\u0435\u043B\u0430, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0435\u0439 \u0432 \u0430\u0445\u0430\u043C\u043A\u0430\u0440\u0435. \u0412\u044B\u0441\u043B\u0443\u0448\u0430\u0439 \u043E \u0432\u043E\u0441\u044C\u043C\u0435\u0440\u043A\u0435 \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A\u0430 \u0431\u043E\u0433\u043E\u0432 \u0432 \u0431\u0443\u0434\u0434\u0445\u0438, \u043E\u043F\u0438\u0441\u0430\u043D\u043D\u0443\u044E \u041C\u043D\u043E\u044E .</p></div><div class="stanza"><a href="#s5.23" id="s5.23" class="num">5.23</a><p>\u041F\u0430\u0439\u0448\u0430\u0447\u0430, \u0420\u0430\u043A\u0448\u0430\u0441, \u042F\u043A\u0448\u0430, \u0413\u0430\u043D\u0434\u0445\u0430\u0440\u0432\u0430, \u0427\u0430\u0439\u043D\u0434\u0440\u0430, \u0421\u0430\u0443\u043C\u044C\u044F, \u041F\u0440\u0430\u043F\u0434\u0436\u0435\u0448\u0430 \u0438 \u0411\u043E\u0440\u0430\u0445\u043C\u0430: \u0442\u0430\u043A\u043E\u0432\u0430 \u044D\u0442\u0430 \u0432\u043E\u0441\u044C\u043C\u0435\u0440\u043A\u0430 .</p></div><div class="stanza"><a href="#s5.24-26" id="s5.24-26" class="num">5.24-26</a><p>\u0412\u043E\u0441\u044C\u043C\u0435\u0440\u043A\u0430 \u0439\u043E\u0433\u0438 (\u043D\u0430\u0445\u043E\u0434\u0438\u0442\u0441\u044F) \u0432 \u043F\u0440\u0430\u0434\u0445\u0430\u043D\u0435. \u0422\u0430\u043C \u0432 \u043D\u0430\u0447\u0430\u043B\u0435 \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435. \u041A\u0440\u0438\u0442\u0430, \u0412\u0430\u0439\u0431\u0445\u0430\u0432\u0430, \u0411\u0440\u0430\u0445\u043C\u0430, \u0412\u0430\u0439\u0448\u043D\u0430\u0432\u0430, \u041A\u0430\u0443\u043C\u0430\u0440\u0430, \u0410\u0443\u043C\u0430, \u0428\u0440\u0430\u0439\u043A\u0430\u043D\u0442\u0445\u0430: \u0442\u0430\u043A\u043E\u0432\u0430 \u0432\u043E\u0441\u044C\u043C\u0435\u0440\u043A\u0430 \u0439\u043E\u0433\u0438. \u0412 \u041F\u0443\u0440\u0443\u0448\u0435 (\u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0442) \u0412\u0430\u043C\u0430, \u0411\u0445\u0438\u043C\u0430, \u0423\u0433\u0440\u0430, \u0411\u0445\u0430\u0432\u0430, \u0418\u0448\u0430\u043D\u0430, \u042D\u043A\u0430\u0432\u0438\u0440\u0430, \u041F\u0440\u0430\u0447\u0430\u043D\u0434\u0430 \u0438 \u041C\u0430\u0433\u0445\u0430\u0432\u0430. \u0414\u0430\u043B\u0435\u0435, \u0432 \u0432\u0438\u0434\u044C\u044F (\u0442\u0430\u0442\u0442\u0432\u0435) \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0442 (\u0440\u0430\u0441\u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u044F\u044F) \u043F\u043E\u0432\u0441\u044E\u0434\u0443 \u0441\u0432\u0435\u0442: \u0410\u0434\u0436\u0430, \u0410\u043D\u0430\u0442\u0430, \u042D\u043A\u0430\u0448\u0438\u0432\u0430, \u041A\u0440\u043E\u0434\u0445\u0430 \u0438 \u0427\u0430\u043D\u0434\u0430. \u0412 \u043A\u0430\u043B\u0410 \u0442\u0430\u0442\u0442\u0432\u0435 \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u044B \u0421\u0443\u0440\u0430\u043F\u0430, \u0410\u043D\u0442\u0430\u043A\u0430, \u042D\u043A\u0430\u0432\u0438\u0440\u0430, \u0428\u0438\u043A\u0445\u0430\u043D\u0434\u0438, \u0418\u0448\u0430, \u0428\u0440\u0438\u043A\u0430\u043D\u0442\u0445\u0430, \u043E\u0445\u0432\u0430\u0447\u0435\u043D\u043D\u044B\u0435 \u0412\u0440\u0435\u043C\u0435\u043D\u0435\u043C .</p></div><div class="stanza"><a href="#s5.27" id="s5.27" class="num">5.27</a><p>\u041D\u0438\u0447\u0438\u043D\u0430\u044F \u0441 \u041C\u0430\u0445\u0430\u0442\u0435\u0434\u0436\u0430\u0441\u0430 (\u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0442) \u041C\u0430\u043D\u0434\u0430\u043B\u0435\u0448\u0430\u043D\u0430, \u0434\u0430\u043B\u0435\u0435 \u0441\u043B\u0435\u0434\u0443\u044E\u0442 \u0412\u0430\u043C\u0430\u0434\u0435\u0432\u0430, \u0411\u0445\u0430\u0432\u0430 \u0438 \u0423\u0442\u0431\u0445\u0430\u0432\u0430. \u042D\u0442\u0438 (\u043C\u0438\u0440\u044B) \u043D\u0430\u0445\u043E\u0434\u044F\u0442\u0441\u044F \u0432 \u043C\u0430\u0439\u0430\u0442\u0430\u0442\u0442\u0432\u0435 .</p></div><div class="stanza"><a href="#s5.28-32" id="s5.28-32" class="num">5.28-32</a><p>\u042D\u043A\u0430\u043F\u0438\u043D\u0433\u0435\u043A\u0448\u0430\u043D\u0430, \u0418\u0448\u0430\u043D\u0430, \u0411\u0445\u0443\u0432\u0430\u043D\u0435\u0448\u0430, \u0410\u043D\u0433\u0443\u0448\u0442\u0445\u0430\u043C\u0430\u0442\u0440\u0430 \u0438 \u041A\u0430\u043B\u0430\u043D\u0430\u043B\u0430 -\u044D\u0442\u0438 \u043F\u044F\u0442\u044C \u043C\u0438\u0440\u043E\u0432 \u043E\u0434\u0438\u043D \u0437\u0430 \u0434\u0440\u0443\u0433\u0438\u043C \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u044B \u043C\u0443\u0434\u0440\u044B\u043C, (\u043A\u0430\u043A \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0438\u0435) \u0432 \u0432\u0438\u0434\u044C\u044F \u0442\u0430\u0442\u0442\u0432\u0435. \u041D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u0425\u0430\u043B\u0430\u0445\u0430\u043B\u044B, \u0434\u0430\u043B\u0435\u0435 \u0441\u043B\u0435\u0434\u0443\u044E\u0442 \u041A\u0440\u043E\u0434\u0445\u0430, \u0420\u0443\u0434\u0440\u0430, \u0410\u043C\u0431\u0438\u043A\u0430, \u0410\u0433\u0445\u043E\u0440\u0430 \u0438 \u0412\u0430\u043C\u0430\u0434\u0435\u0432\u0430, (\u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0438\u0435) \u0432 \u0418\u0448\u0432\u0430\u0440\u0430 (\u0442\u0430\u0442\u0442\u0432\u0435). \u0421\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0435 \u043C\u0438\u0440\u044B \u0437\u0430\u0432\u0435\u0440\u0448\u0430\u044E\u0442\u0441\u044F \u043D\u0430 \u0410\u0433\u0445\u043E\u0440\u0435 \u0435\u0441\u0442\u044C \u0432\u0435\u043B\u0438\u043A\u0438\u0435 \u0432\u043B\u0430\u0434\u044B\u043A\u0438 \u044D\u0442\u043E - \u0420\u0430\u0443\u0434\u0440\u0438, \u0414\u0436\u0435\u0448\u0442\u0445\u0430, \u0412\u0430\u043C\u0430, \u0428\u0430\u043A\u0442\u0438 \u0438 \u0421\u0430\u0434\u0430\u0448\u0438\u0432\u0430. \u042D\u0442\u0438 \u043F\u044F\u0442\u044C \u043C\u0438\u0440\u043E\u0432 \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u044B \u043C\u0443\u0434\u0440\u044B\u043C \u0432 \u0441\u0430\u043A\u0430\u043B\u0435 .</p></div><div class="stanza"><a href="#s5.33" id="s5.33" class="num">5.33</a><p>\u0418\u0442\u0430\u043A, \u0432\u043E \u0432\u0441\u0435\u0445 \u0442\u0430\u0442\u0442\u0432\u0430\u0445 \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u043E 108 \u043C\u0438\u0440\u043E\u0432, \u043E\u043F\u0438\u0441\u0430\u043D\u043D\u044B\u0445 \u0432\u043A\u0440\u0430\u0442\u0446\u0435, \u0430 \u043D\u0435 \u043F\u043E\u0434\u0440\u043E\u0431\u043D\u043E .</p></div><div class="stanza"><a href="#s5.34-35" id="s5.34-35" class="num">5.34-35</a><p>\u0421\u0432\u043E\u0435\u0439 \u0447\u0438\u0441\u0442\u043E\u0442\u043E\u044E, \u043E\u043D\u0438 \u0432\u0441\u0435 \u043E\u0447\u0438\u0449\u0430\u044E\u0442, \u0431\u0435\u0437 \u0441\u043E\u043C\u043D\u0435\u043D\u0438\u044F. \u0412\u0435\u043B\u0438\u043A\u043E\u043C\u0443\u0434\u0440\u044B\u0439, \u0434\u0435\u043B\u0430\u044F \u0432\u0441\u0435 \u043F\u0443\u0442\u0438 \u0447\u0438\u0441\u0442\u044B\u043C\u0438, \u043E\u0447\u0438\u0449\u0430\u044F\u0441\u044C \u0432 \u0441\u0430\u043A\u0430\u043B\u0435 \u043F\u0443\u0441\u0442\u044C \u0443\u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u043E \u0441 \u0428\u0438\u0432\u043E\u0439. \u0417\u043D\u0430\u044E\u0449\u0438\u0439 \u0439\u043E\u0433\u0443 \u0438 \u0436\u0435\u043B\u0430\u044E\u0449\u0438\u0439 \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u044F, \u043F\u0443\u0441\u0442\u044C \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0443\u0435\u0442 \u0439\u043E\u0433\u0443, \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u044F \u0441\u0430\u043A\u0430\u043B\u0443. \u0422\u0430\u043A\u043E\u0432 \u044D\u0442\u043E\u0442 \u043F\u0443\u0442\u044C \u043C\u0438\u0440\u043E\u0432 \u043F\u0440\u043E\u0432\u043E\u0437\u0433\u043B\u0430\u0448\u0435\u043D\u043D\u044B\u0439 \u041C\u043D\u043E\u044E .</p></div><p>\u0422\u0430\u043A\u043E\u0432\u0430 \u0432 \u0441\u0432\u044F\u0449\u0435\u043D\u043D\u043E\u0439 \xAB\u041C\u0430\u043B\u0438\u043D\u0438 \u0432\u0438\u0434\u0436\u0430\u0439\u043E\u0442\u0442\u0430\u0440\u0430 \u0442\u0430\u043D\u0442\u0440\u0435\xBB \u043F\u044F\u0442\u0430\u044F \u0433\u043B\u0430\u0432\u0430.</p>',20),c=[n];function e(p,l,v,r,_,m){return i(),a("div",null,c)}var h=s(t,[["render",e]]);export{u as __pageData,h as default};
